arguments.command:
cd /tmp/sv-fbba1365ed314c56928803a62240ca68 && cat > /tmp/parse_binlog.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
  </ItemGroup>
</Project>
EOF
cat > /tmp/parse_binlog.cs << 'CEOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");

// Collect all errors
var errors = new List<(string project, string code, string message, string file, int line)>();
build.VisitAllChildren<Error>(e => {
    string project = "";
    var node = e.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        if (node is Target t && t.Project is Project tp) { project = tp.Name; break; }
        node = node.Parent as BaseNode;
    }
    errors.Add((project, e.Code ?? "", e.Text ?? e.ToString(), e.File ?? "", e.LineNumber));
});

Console.WriteLine($"\n=== ERRORS ({errors.Count} total) ===");
foreach (var g in errors.GroupBy(e => e.project)) {
    Console.WriteLine($"\n--- Project: {g.Key} ---");
    foreach (var e in g) {
        Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
    }
}

// Collect all warnings
var warnings = new List<(string project, string code, string message)>();
build.VisitAllChildren<Warning>(w => {
    string project = "";
    var node = w.Parent;
    while (node != null) {
        if (node is Project p) { project = p.Name; break; }
        if (node is Target t && t.Project is Project tp) { project = tp.Name; break; }
        node = node.Parent as BaseNode;
    }
    warnings.Add((project, w.Code ?? "", w.Text ?? w.ToString()));
});

if (warnings.Any()) {
    Console.WriteLine($"\n=== WARNINGS ({warnings.Count} total) ===");
    foreach (var g in warnings.GroupBy(w => w.project)) {
        Console.WriteLine($"\n--- Project: {g.Key} ---");
        foreach (var w in g) {
            Console.WriteLine($"  [{w.code}] {w.message}");
        }
    }
}

// Show project dependency info
Console.WriteLine("\n=== PROJECT STRUCTURE ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  Project: {p.Name} (Succeeded={p.Succeeded})");
});
CEOF
