    if (item.Name == "ProjectReference") {
        string project = "";
        TreeNode node = item.Parent;
        while (node != null) {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
        }
        foreach (var child in item.Children) {
            Console.WriteLine($"  {project}: {child}");
        }
    }
});

// Check NuGet restore output
Console.WriteLine("\n=== NUGET / RESTORE MESSAGES ===");
build.VisitAllChildren<Message>(m => {
    if (m.Text != null && (m.Text.Contains("Newtonsoft") || m.Text.Contains("restore") || m.Text.Contains("NU"))) {
        string project = "";
        TreeNode node = m.Parent;
        while (node != null) {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
