        // Look for command line or parameters
        t.VisitAllChildren<Message>(m => {
            if (m.Text != null && m.Text.Length < 2000)
                Console.WriteLine($"    MSG: {m.Text}");
        });
        t.VisitAllChildren<Property>(p2 => {
            Console.WriteLine($"    PROP: {p2.Name} = {p2.Value?.Substring(0, Math.Min(200, p2.Value?.Length ?? 0))}");
        });
    }
});

