build.VisitAllChildren<Message>(m => {
    if (m.Text != null && m.Text.Contains("BuildResponseFile")) {
        Console.WriteLine($"  {m.Text.Substring(0, Math.Min(500, m.Text.Length))}");
    }
});

// Check project.assets.json for Newtonsoft
Console.WriteLine("\n=== project.assets.json (Services) - Newtonsoft check ===");
var assetsPath = "/tmp/binlog_reconstructed/tmp/sv-fbba1365ed314c56928803a62240ca68/Services/obj/project.assets.json";
if (System.IO.File.Exists(assetsPath)) {
    var content = System.IO.File.ReadAllText(assetsPath);
    Console.WriteLine($"  File size: {content.Length}");
    Console.WriteLine($"  Contains Newtonsoft: {content.Contains("Newtonsoft")}");
    // Show libraries section
    if (content.Contains("Newtonsoft")) {
        var idx = content.IndexOf("Newtonsoft");
        Console.WriteLine($"  Context: ...{content.Substring(Math.Max(0, idx-50), Math.Min(200, content.Length - Math.Max(0, idx-50)))}...");
    }
}
