var build = BinaryLog.ReadBuild(binlogPath);

// Get CSC command for Services, extract /reference: args only
build.VisitAllChildren<Task>(t => {
    if (t.Name == "Csc") {
        string project = "";
        TreeNode node = t.Parent;
        while (node != null) {
            if (node is Project p) { project = p.Name; break; }
            node = node.Parent;
        }
        if (project == "Services.csproj") {
            t.VisitAllChildren<Property>(p2 => {
                if (p2.Name == "CommandLineArguments") {
                    var parts = p2.Value.Split(' ');
                    Console.WriteLine("=== REFERENCES passed to Services.csproj CSC ===");
                    foreach (var part in parts) {
                        if (part.StartsWith("/reference:"))
                            Console.WriteLine($"  {part}");
                    }
                    Console.WriteLine("\n=== SOURCE FILES passed to Services.csproj CSC ===");
                    foreach (var part in parts) {
                        if (part.EndsWith(".cs") || part.EndsWith(".cs\""))
                            Console.WriteLine($"  {part}");
                    }
                }
            });
        }
    }
});

// Show assets.json for Services
